export{default as ThemeManager,ThemeToggle,isDark,toggle as toggleTheme}from '../core/theme-manager.js';export{KeyboardShortcutsComponent}from './keyboard-shortcuts.js';export{injectKeyboardShortcutsStyles}from './keyboard-shortcuts.js';export{SkeletonLoaderComponent}from './skeleton-loader.js';export{injectSkeletonLoaderStyles}from './skeleton-loader.js';export{NotificationBellComponent}from './bell-component.js';export{NotificationPanelComponent}from './notification-panel.js';export{injectNotificationStyles}from './notification-panel.js';export function initAllUXComponents(){const keyboardShortcuts=new KeyboardShortcutsComponent();const skeletonLoader=new SkeletonLoaderComponent();const notificationPanel=new NotificationPanelComponent();const notificationBell=new NotificationBellComponent({defaultNotifications: [{id: '1',title: 'Chiến dịch mới được tạo',message: 'Chiến dịch "Tết 2026" đã được khởi tạo thành công.',icon: 'campaign',time: Date.now()-300000,read: false,type: 'success'},{id: '2',title: 'Lead mới từ Facebook',message: 'Nguyễn Văn A-CEO tại ABC Company',icon: 'person_add',time: Date.now()-3600000,read: false,type: 'info'}]});notificationPanel.init(notificationBell);notificationBell.init(notificationPanel);keyboardShortcuts.init();skeletonLoader.init();return{keyboardShortcuts,skeletonLoader,notificationBell,notificationPanel};}export function initDarkMode(){injectDarkModeStyles();const darkMode=new DarkModeComponent();darkMode.init();return darkMode;}export function initKeyboardShortcuts(){injectKeyboardShortcutsStyles();const shortcuts=new KeyboardShortcutsComponent();shortcuts.init();return shortcuts;}export function initSkeletonLoader(){injectSkeletonLoaderStyles();const skeleton=new SkeletonLoaderComponent();skeleton.init();return skeleton;}